        assert_eq!(
            snapshot.status_for("Archive2.exe").map(|row| row.detected_status),
            Some(DowngraderInstallStatus::NotFound)
        );
        assert!(snapshot.unknown_game);
        assert!(snapshot.unknown_creation_kit);
    }

